-- ملء محتوى عنقود "القواعد الفقهية" (qawaid-fiqhiyya) — 4 تصنيفات فرعية،
-- كلها draft (استنفاد كامل للعنقود): القواعد الخمس الكبرى، القواعد
-- الكلية والتابعة، الضوابط الفقهية، تطبيقات في العبادات والمعاملات
-- المعاصرة.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس usul-fiqh/mustalah-hadith
-- (تعريفي موجز: قسم body + قسم examples).
-- المصادر المعتمدة: الأشباه والنظائر للسيوطي، الوجيز في إيضاح قواعد
-- الفقه الكلية لمحمد صدقي البورنو، القواعد لابن رجب الحنبلي.
-- حديثان استُشهد بهما، تحقَّقا حرفياً عبر WebSearch قبل الإدراج (متفق
-- عليهما، صحيحان): "إنما الأعمال بالنيات..." (البخاري ومسلم)، و"من نسي
-- وهو صائم فأكل أو شرب فليتم صومه فإنما أطعمه الله وسقاه" (البخاري 6669
-- ومسلم 1155).
-- آيتان تحقَّقتا حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: البقرة 173، البقرة 286.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأربعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) القواعد الخمس الكبرى
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1dc00e61-3873-4fac-b384-c956214aa8f2' AND title='القواعد الفقهية الخمس الكبرى') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('القواعد الفقهية الخمس الكبرى', 'تعريف موجز بالقواعد الفقهية الخمس الكبرى التي تُبنى عليها فروع الفقه الإسلامي', '1dc00e61-3873-4fac-b384-c956214aa8f2', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'القواعد الخمس التي أجمع الفقهاء على اعتبارها', 'اتفق الفقهاء على خمس قواعد فقهية كبرى تندرج تحتها أكثر مسائل الفقه الفرعية: الأولى "الأمور بمقاصدها"، أي أن الحكم على الفعل يتبع نية فاعله؛ الثانية "اليقين لا يزول بالشك"، فما ثبت بيقين لا يُرفع بمجرد الشك؛ الثالثة "المشقة تجلب التيسير"، فكلما اشتدت المشقة خُفف الحكم؛ الرابعة "الضرر يزال"، فكل ضرر واقع يجب السعي في إزالته أو تخفيفه؛ الخامسة "العادة محكَّمة"، فما تعارفه الناس واستقر عملهم عليه يُعتد به عند عدم النص. وهذه الخمس هي عمود الفقه الذي تُرد إليه سائر القواعد المتفرعة.', 1),
    (v_lesson, 'examples', 'أصل قاعدة "الأمور بمقاصدها"', 'الأصل في هذه القاعدة حديث النبي صلى الله عليه وسلم: "إنما الأعمال بالنيات، وإنما لكل امرئ ما نوى، فمن كانت هجرته إلى الله ورسوله فهجرته إلى الله ورسوله، ومن كانت هجرته لدنيا يصيبها أو امرأة ينكحها فهجرته إلى ما هاجر إليه" (متفق عليه)، وهو الحديث الذي جعله العلماء ميزانًا للأعمال الباطنة وأصلاً لهذه القاعدة الكبرى.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الأشباه والنظائر — جلال الدين السيوطي', 1);
  END IF;

  -- 2) القواعد الكلية والتابعة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='6c41a3a4-a34c-43c4-b025-99a895bfafd4' AND title='القواعد الكلية والقواعد المتفرعة عنها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('القواعد الكلية والقواعد المتفرعة عنها', 'تعريف موجز بالقواعد الفقهية المتفرعة عن القواعد الخمس الكبرى', '6c41a3a4-a34c-43c4-b025-99a895bfafd4', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تفرع القواعد عن الأصول الخمسة', 'تتفرع عن كل قاعدة من القواعد الخمس الكبرى قواعد أخص منها تفصّل تطبيقها، فتحت قاعدة "المشقة تجلب التيسير" تندرج: "الضرورات تبيح المحظورات"، و"ما أبيح للضرورة يقدر بقدرها"، و"الحاجة تنزل منزلة الضرورة عامة كانت أو خاصة". وتحت قاعدة "الضرر يزال" تندرج: "الضرر لا يزال بمثله"، و"الضرر الأشد يزال بالضرر الأخف"، و"درء المفاسد أولى من جلب المصالح". وتحت قاعدة "اليقين لا يزول بالشك" تندرج: "الأصل بقاء ما كان على ما كان"، و"الأصل براءة الذمة".', 1),
    (v_lesson, 'examples', 'مثال قرآني على قاعدة "الضرورات تبيح المحظورات"', 'قال تعالى: ﴿إِنَّمَا حَرَّمَ عَلَيْكُمُ الْمَيْتَةَ وَالدَّمَ وَلَحْمَ الْخِنزِيرِ وَمَا أُهِلَّ بِهِ لِغَيْرِ اللَّهِ فَمَنِ اضْطُرَّ غَيْرَ بَاغٍ وَلَا عَادٍ فَلَا إِثْمَ عَلَيْهِ إِنَّ اللَّهَ غَفُورٌ رَّحِيمٌ﴾ (البقرة: 173)، وهي الآية التي استنبط منها الفقهاء قاعدة "الضرورات تبيح المحظورات" وقيّدوها بقيد "بقدرها" المأخوذ من نفس السياق.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الوجيز في إيضاح قواعد الفقه الكلية — محمد صدقي بن أحمد البورنو', 1);
  END IF;

  -- 3) الضوابط الفقهية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e2fec8c8-adcb-40c2-add7-2e518b9d7e4a' AND title='الضوابط الفقهية وعلاقتها بالقواعد الفقهية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الضوابط الفقهية وعلاقتها بالقواعد الفقهية', 'تعريف موجز بالضابط الفقهي والفرق بينه وبين القاعدة الفقهية', 'e2fec8c8-adcb-40c2-add7-2e518b9d7e4a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الفرق بين الضابط الفقهي والقاعدة الفقهية', 'الضابط الفقهي حكم كلي ينطبق على جزئيات كثيرة، لكنه محصور في باب واحد من أبواب الفقه، بخلاف القاعدة الفقهية التي تجمع فروعًا من أبواب متعددة؛ فقولهم "كل عبادة تبطل بالحدث تبطل بالردة" ضابط خاص بباب العبادات، وقولهم "كل عقد فاسد لا يفيد الملك" ضابط خاص بباب المعاملات، بينما قاعدة مثل "المشقة تجلب التيسير" تجري في العبادات والمعاملات والعقوبات معًا. وفائدة الضوابط جمع مسائل الباب الواحد تحت حكم جامع يسهّل ضبطها ومقارنتها.', 1),
    (v_lesson, 'examples', 'مثال ضابط خاص بباب الصيام', 'من الضوابط الخاصة بباب الصيام: أن الناسي لا حكم لفعله في مبطلات الصوم، ودليله حديث النبي صلى الله عليه وسلم: "من نسي وهو صائم فأكل أو شرب فليتم صومه فإنما أطعمه الله وسقاه" (رواه البخاري ومسلم)، فهذا ضابط محصور في باب الصيام لا يتعداه إلى سائر أبواب الفقه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'القواعد — ابن رجب الحنبلي', 1);
  END IF;

  -- 4) تطبيقات في العبادات والمعاملات المعاصرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='88e85130-d289-459b-ba8c-3be5986ab2e1' AND title='تطبيقات معاصرة للقواعد الفقهية في العبادات والمعاملات') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تطبيقات معاصرة للقواعد الفقهية في العبادات والمعاملات', 'تعريف موجز بتطبيقات القواعد الفقهية الكبرى في مسائل عبادية ومالية معاصرة', '88e85130-d289-459b-ba8c-3be5986ab2e1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تطبيقات معاصرة على القواعد الكبرى', 'تُستخدم القواعد الفقهية الكبرى أداة لتخريج مسائل مستجدة: فقاعدة "المشقة تجلب التيسير" هي أساس رخص المرضى وأصحاب الأعذار، كالتيمم بدل الوضوء لمن يتعذر عليه استعمال الماء لعلة طبية، والجمع والقصر في السفر؛ وقاعدة "الضرر يزال" أساس أنظمة حماية المستهلك ومنع الغرر والاحتكار في المعاملات المالية المعاصرة؛ وقاعدة "العادة محكَّمة" أساس الرجوع إلى العرف التجاري السائد عند تفسير العقود وسكوت النص، كالعرف المصرفي في تحديد آجال الوفاء بالالتزامات.', 1),
    (v_lesson, 'examples', 'الأصل القرآني لرفع الحرج عن أصحاب الأعذار', 'قال تعالى: ﴿لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا﴾ (البقرة: 286)، وهي الأصل العام الذي تُبنى عليه سائر رخص أصحاب الأعذار المعاصرة، فكل تكليف يُقدَّر بقدر طاقة المكلَّف لا يتجاوزها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'موسوعة القواعد الفقهية — محمد صدقي بن أحمد البورنو', 1);
  END IF;

  -- تحديث حالة التصنيفات الأربعة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
    '1dc00e61-3873-4fac-b384-c956214aa8f2', '6c41a3a4-a34c-43c4-b025-99a895bfafd4',
    'e2fec8c8-adcb-40c2-add7-2e518b9d7e4a', '88e85130-d289-459b-ba8c-3be5986ab2e1'
  );
END $$;
